SELECT DISTINCT user_id
FROM trades
WHERE status = 'completed';

SELECT COUNT(*) AS total_trades, AVG(quantity) AS average_quantity, AVG(price) AS average_price
FROM trades
WHERE trade_type = 'buy';

SELECT DISTINCT u.username, u.role, u.last_login
FROM users u
JOIN trades t ON u.user_id = t.user_id;

SELECT log_time, log_message, user_id, action_type, ip_address, device_type, user_agent 
FROM audit_logs
WHERE log_id = 1;

SELECT trade_id, trade_time, trade_type, quantity, price, status, commission, note
FROM trades
WHERE user_id = 0;

SELECT stock_name, market_cap
FROM stocks
WHERE sector = 'Technology' AND industry = 'Software' AND CAST(REPLACE(market_cap, ',', '') AS REAL) > 1000000000000;

SELECT stock_symbol, stock_name, sector, market_cap
FROM stocks
WHERE sector = 'Technology' AND market_cap > '100000000000';
